function minNumberOfBeansToRemove(beans) {
    const count = {};
    for (const bean of beans) {
        if (!count.hasOwnProperty(bean)) {
            count[bean] = 0;
        }
        count[bean]++;
    }

    let min_remove = beans.length;
    for (const [key, value] of Object.entries(count)) {
        let remove = 0;
        for (const [other_key, other_value] of Object.entries(count)) {
            if (other_key !== key) {
                remove += other_value * Math.max(0, other_key - key);
            }
        }
        min_remove = Math.min(min_remove, remove);
    }

    return min_remove;
}
